import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';

export default function EventsByVenue() {
  const navigate = useNavigate();
  const [venues, setVenues] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVenues = async () => {
      try {
        // Fetch all approved events
        const response = await api.get('/events/', { params: { status: 'approved' } });
        const events = response.data.results || response.data;

        // Group events by location (venue)
        const venueMap = {};
        events.forEach(event => {
          const venue = event.location;
          if (!venueMap[venue]) {
            venueMap[venue] = {
              location: venue,
              city: event.city,
              image: event.image,
              events: [],
              address: `${event.location}${event.city ? ', ' + event.city : ''}`
            };
          }
          venueMap[venue].events.push(event);
        });

        // Convert to array and sort by event count
        const venueList = Object.values(venueMap).sort((a, b) => b.events.length - a.events.length);
        setVenues(venueList);
      } catch (error) {
        console.error('Failed to fetch venues:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchVenues();
  }, []);

  if (loading) {
    return (
      <div style={{ background: '#191919' }} className="min-h-screen flex items-center justify-center">
        <p className="text-gray-400">Loading venues...</p>
      </div>
    );
  }

  return (
    <div style={{ background: '#191919' }} className="min-h-screen">
      {/* Page Header */}
      <div className="border-b" style={{ borderColor: '#2a2a2a', background: '#0a0a0a', padding: '32px 24px' }}>
        <div className="max-w-7xl mx-auto">
          <h1 className="text-5xl font-bold text-white mb-2">Events by Venue</h1>
          <p className="text-gray-400">Discover amazing venues hosting events in your area</p>
        </div>
      </div>

      {/* Venues Grid */}
      <div className="max-w-7xl mx-auto px-6 py-16">
        {venues.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {venues.map((venue, index) => (
              <div
                key={index}
                onClick={() => navigate(`/`, { state: { filterVenue: venue.location } })}
                className="rounded-lg overflow-hidden cursor-pointer group transition-all hover:shadow-xl"
                style={{ background: '#1d191e', border: '1px solid #2a2a2a' }}
              >
                {/* Venue Image */}
                <div className="relative overflow-hidden" style={{ height: '220px' }}>
                  <img
                    src={venue.image || 'https://via.placeholder.com/400x220?text=' + encodeURIComponent(venue.location)}
                    alt={venue.location}
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                  />
                  {/* Event Count Badge */}
                  <div
                    className="absolute top-3 right-3 px-3 py-1 rounded-full font-bold text-white text-sm"
                    style={{ background: '#ff00e0' }}
                  >
                    {venue.events.length} {venue.events.length === 1 ? 'Event' : 'Events'}
                  </div>
                </div>

                {/* Venue Info */}
                <div className="p-5">
                  <h3 className="text-xl font-bold text-white mb-2 truncate">{venue.location}</h3>
                  <p className="text-gray-400 text-sm mb-3 line-clamp-2 flex items-start gap-2">
                    <span style={{ color: '#ff00e0' }} className="flex-shrink-0 mt-0.5">📍</span>
                    <span>{venue.address}</span>
                  </p>

                  {/* Upcoming Events Label */}
                  <p className="text-gray-500 text-xs font-semibold mb-3">
                    {venue.events.length} UPCOMING {venue.events.length === 1 ? 'EVENT' : 'EVENTS'}
                  </p>

                  {/* Browse Button */}
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      navigate(`/`, { state: { filterVenue: venue.location } });
                    }}
                    className="w-full py-2 px-4 rounded-lg text-white font-semibold transition-all"
                    style={{
                      background: '#ff00e0',
                      border: '2px solid #ff00e0',
                      color: '#fff'
                    }}
                    onMouseEnter={(e) => {
                      e.target.style.background = 'transparent';
                      e.target.style.color = '#ff00e0';
                    }}
                    onMouseLeave={(e) => {
                      e.target.style.background = '#ff00e0';
                      e.target.style.color = '#fff';
                    }}
                  >
                    Browse Events →
                  </button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-16">
            <p className="text-gray-400 text-lg">No venues with events found</p>
          </div>
        )}
      </div>
    </div>
  );
}
